import React, { useState, useEffect } from 'react';
import { ethers } from 'ethers';
import { useWallet } from './context/WalletContext';
import { getTokenBalance, getPoolInfo, getLPBalance, swap as swapTokens, addLiquidity as addLiquidityFunc, removeLiquidity as removeLiquidityFunc, getTokenContract, getPoolContract } from './hooks/useContracts';

const Header = ({ openModal }) => {
  const { account, balance, isConnected, connectWallet, disconnectWallet } = useWallet();

  const formatAddress = (addr) => {
    if (!addr) return '';
    return `${addr.substring(0, 6)}...${addr.substring(addr.length - 4)}`;
  };

  return (
    <div style={styles.header}>
      <div style={styles.headerContent}>
        <div style={styles.logo}>
          <span style={{ fontSize: '24px', marginRight: '8px' }}>📊</span>
          <span style={styles.logoText}>DeFi DEX</span>
        </div>
        
        <div style={styles.nav}>
          <button 
            style={styles.navButton}
            onClick={() => openModal('swap')}
          >
            🔄 Swap
          </button>
          <button 
            style={styles.navButton}
            onClick={() => openModal('liquidity')}
          >
            💧 Liquidity
          </button>
          <button 
            style={styles.navButton}
            onClick={() => openModal('positions')}
          >
            📍 Positions
          </button>
        </div>

        <div style={styles.wallet}>
          {isConnected ? (
            <div style={styles.connectedWallet}>
              <div style={styles.balanceInfo}>
                <div style={styles.balanceAmount}>{parseFloat(balance).toFixed(3)} ETH</div>
                <div style={styles.balanceLabel}>Balance</div>
              </div>
              <span style={styles.address}>{formatAddress(account)}</span>
              <button
                style={{ ...styles.button, ...styles.disconnectBtn }}
                onClick={disconnectWallet}
              >
                Disconnect
              </button>
            </div>
          ) : (
            <button
              style={{ ...styles.button, ...styles.connectBtn }}
              onClick={connectWallet}
            >
              Connect MetaMask
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

const SwapModal = ({ isOpen, onClose, poolAddress, tokens }) => {
  const { provider, signer } = useWallet();
  const [amountIn, setAmountIn] = useState('');
  const [slippage, setSlippage] = useState('0.5');
  const [isLoading, setIsLoading] = useState(false);
  const [txStatus, setTxStatus] = useState(null);
  const [estimatedOut, setEstimatedOut] = useState('0');

  if (!isOpen) return null;

  const handleClose = () => {
    setAmountIn('');
    setTxStatus(null);
    onClose();
  };

  return (
    <div style={styles.modalOverlay} onClick={handleClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <h2>🔄 Swap Tokens</h2>
          <button style={styles.closeBtn} onClick={handleClose}>✕</button>
        </div>

        <div style={styles.modalContent}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>You Pay</label>
            <input
              type="number"
              placeholder="0.0"
              value={amountIn}
              onChange={(e) => setAmountIn(e.target.value)}
              style={styles.input}
            />
            <div style={styles.tokenInfo}>{tokens?.token0}</div>
          </div>

          <div style={styles.swapArrow}>⬇️</div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>You Receive</label>
            <input
              type="text"
              value={estimatedOut}
              disabled
              style={{ ...styles.input, ...styles.disabledInput }}
            />
            <div style={styles.tokenInfo}>{tokens?.token1}</div>
          </div>

          <div style={styles.slippageControl}>
            <label style={styles.label}>Slippage Tolerance</label>
            <div style={styles.slippageOptions}>
              {['0.1', '0.5', '1.0'].map((val) => (
                <button
                  key={val}
                  style={{
                    ...styles.slippageBtn,
                    ...(slippage === val ? styles.slippageBtnActive : {}),
                  }}
                  onClick={() => setSlippage(val)}
                >
                  {val}%
                </button>
              ))}
              <input
                type="number"
                value={slippage}
                onChange={(e) => setSlippage(e.target.value)}
                style={styles.slippageInput}
              />
            </div>
          </div>

          {txStatus && (
            <div style={{
              ...styles.txStatus,
              backgroundColor: txStatus.success ? '#10b981' : '#ef4444',
            }}>
              {txStatus.message}
            </div>
          )}

          <button
            style={{...styles.button, ...styles.primaryBtn}}
            onClick={() => {}}
            disabled={isLoading || !amountIn}
          >
            {isLoading ? 'Processing...' : 'Swap'}
          </button>
        </div>
      </div>
    </div>
  );
};

const LiquidityModal = ({ isOpen, onClose, poolAddress, tokens }) => {
  const [tab, setTab] = useState('add');
  const [amount0, setAmount0] = useState('');
  const [amount1, setAmount1] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [txStatus, setTxStatus] = useState(null);

  if (!isOpen) return null;

  const handleClose = () => {
    setAmount0('');
    setAmount1('');
    setTxStatus(null);
    onClose();
  };

  return (
    <div style={styles.modalOverlay} onClick={handleClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <h2>💧 Liquidity Management</h2>
          <button style={styles.closeBtn} onClick={handleClose}>✕</button>
        </div>

        <div style={styles.tabs}>
          <button
            style={{
              ...styles.tab,
              ...(tab === 'add' ? styles.tabActive : {}),
            }}
            onClick={() => setTab('add')}
          >
            Add Liquidity
          </button>
          <button
            style={{
              ...styles.tab,
              ...(tab === 'remove' ? styles.tabActive : {}),
            }}
            onClick={() => setTab('remove')}
          >
            Remove Liquidity
          </button>
        </div>

        <div style={styles.modalContent}>
          {tab === 'add' ? (
            <>
              <div style={styles.inputGroup}>
                <label style={styles.label}>{tokens?.token0}</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount0}
                  onChange={(e) => setAmount0(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.plus}>+</div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>{tokens?.token1}</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount1}
                  onChange={(e) => setAmount1(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.info}>
                <strong>You will receive LP tokens representing your position</strong>
              </div>
            </>
          ) : (
            <>
              <div style={styles.inputGroup}>
                <label style={styles.label}>LP Tokens to Remove</label>
                <input
                  type="number"
                  placeholder="0.0"
                  value={amount0}
                  onChange={(e) => setAmount0(e.target.value)}
                  style={styles.input}
                />
              </div>

              <div style={styles.info}>
                <strong>You will receive both tokens back proportionally</strong>
              </div>
            </>
          )}

          {txStatus && (
            <div style={{
              ...styles.txStatus,
              backgroundColor: txStatus.success ? '#10b981' : '#ef4444',
            }}>
              {txStatus.message}
            </div>
          )}

          <button
            style={{...styles.button, ...styles.primaryBtn}}
            onClick={() => {}}
            disabled={isLoading}
          >
            {isLoading ? 'Processing...' : (tab === 'add' ? 'Add Liquidity' : 'Remove Liquidity')}
          </button>
        </div>
      </div>
    </div>
  );
};

const PositionsModal = ({ isOpen, onClose, poolAddress }) => {
  const { account, provider } = useWallet();
  const [positions, setPositions] = useState([]);
  const [isLoading, setIsLoading] = useState(false);

  if (!isOpen) return null;

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <h2>📍 Your Positions</h2>
          <button style={styles.closeBtn} onClick={onClose}>✕</button>
        </div>

        <div style={styles.modalContent}>
          {positions.length === 0 ? (
            <div style={styles.emptyState}>
              <p>No active positions</p>
              <p style={{ fontSize: '12px', marginTop: '8px', color: '#9ca3af' }}>
                Add liquidity to start earning fees
              </p>
            </div>
          ) : (
            <div>
              {positions.map((pos, idx) => (
                <div key={idx} style={styles.positionCard}>
                  <div style={styles.positionInfo}>
                    <strong>{pos.token0}/{pos.token1}</strong>
                    <div style={styles.positionDetails}>
                      LP Tokens: {pos.lpBalance}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const App = () => {
  const [activeModal, setActiveModal] = useState(null);
  const { isConnected } = useWallet();

  const mockPoolInfo = {
    poolAddress: '0x...',
    tokens: {
      token0: 'USDC',
      token1: 'DAI',
    },
  };

  return (
    <div style={styles.app}>
      <Header openModal={setActiveModal} />
      
      <div style={styles.container}>
        <div style={styles.hero}>
          <h1 style={styles.heroTitle}>Welcome to DeFi DEX</h1>
          <p style={styles.heroSubtitle}>Decentralized Exchange & Liquidity Protocol</p>
          
          {!isConnected && (
            <div style={styles.heroAction}>
              <p>Connect your wallet to get started</p>
            </div>
          )}

          {isConnected && (
            <div style={styles.quickStats}>
              <div style={styles.stat}>
                <div style={styles.statLabel}>Total Value Locked</div>
                <div style={styles.statValue}>$2.5M</div>
              </div>
              <div style={styles.stat}>
                <div style={styles.statLabel}>24h Volume</div>
                <div style={styles.statValue}>$1.2M</div>
              </div>
              <div style={styles.stat}>
                <div style={styles.statLabel}>Available Pools</div>
                <div style={styles.statValue}>2</div>
              </div>
            </div>
          )}
        </div>
      </div>

      <SwapModal
        isOpen={activeModal === 'swap'}
        onClose={() => setActiveModal(null)}
        poolAddress={mockPoolInfo.poolAddress}
        tokens={mockPoolInfo.tokens}
      />
      
      <LiquidityModal
        isOpen={activeModal === 'liquidity'}
        onClose={() => setActiveModal(null)}
        poolAddress={mockPoolInfo.poolAddress}
        tokens={mockPoolInfo.tokens}
      />
      
      <PositionsModal
        isOpen={activeModal === 'positions'}
        onClose={() => setActiveModal(null)}
        poolAddress={mockPoolInfo.poolAddress}
      />
    </div>
  );
};

